const express = require('express');
const app = express();
const server = require('http').createServer(app);
const io = require('socket.io')(server);

// Middlewares and settings
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

let players = {};
let scores = {};

io.on('connection', (socket) => {
  console.log('New connection');

  socket.on('join', (username) => {
    if (!players[username]) {
      players[username] = { score: 0, socketId: socket.id };
      io.emit('newPlayer', username);
    } else {
      socket.emit('error', 'Username already taken');
    }
  });

  socket.on('disconnect', () => {
    console.log('Disconnected');

    for (let player in players) {
      if (players[player].socketId === socket.id) {
        delete players[player];
        io.emit('playerLeft', player);
      }
    }
  });

  socket.on('move', (username, score) => {
    if (players[username]) {
      scores[username] = score;
      io.emit('newScore', username, score);
    } else {
      socket.emit('error', 'Invalid username');
    }
  });
});

server.listen(3000, () => {
  console.log('Server listening on port 3000');
});